export const bundledContent: Record<string, string> = {
  "s1-biologia": "# Biologia Aplicada\n\nPrincípios de biologia celular, ecossistemas, microbiologia e biodiversidade com aplicação nos processos de saneamento, saúde ambiental e tratamento de águas.\n\n## Tópicos de Estudo\n\n- Célula: estrutura, função e divisão celular\n- Genética básica e hereditariedade\n- Ecossistemas: cadeias e teias alimentares\n- Ciclos biogeoquímicos (água, carbono, nitrogênio, fósforo)\n- Microbiologia: bactérias, vírus, fungos e protozoários\n- Indicadores biológicos de qualidade ambiental\n- Biologia aquática e organismos em corpos d'água\n- Noções de saúde pública e doenças de veiculação hídrica\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ODUM, E. P.; BARRETT, G. W. Fundamentos de Ecologia. São Paulo: Thomson, 2008.\n- TORTORA, G. J.; FUNKE, B. R.; CASE, C. L. Microbiologia. 10ª ed. Porto Alegre: Artmed, 2012.\n- CAMPBELL, N. A.; REECE, J. B. Biologia. 8ª ed. Porto Alegre: Artmed, 2010.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- MADIGAN, M. T. et al. Microbiologia de Brock. 14ª ed. Porto Alegre: Artmed, 2016.\n- RICKLEFS, R. E. A Economia da Natureza. 6ª ed. Rio de Janeiro: Guanabara Koogan, 2010.",
  "s1-calculo": "# Cálculo\n\nFunções reais de uma variável real: limites, continuidade, derivadas, aplicações da derivada, integrais e suas aplicações em problemas de engenharia e saneamento ambiental.\n\n## Tópicos de Estudo\n\n- Funções reais de uma variável: domínio, imagem e gráficos\n- Limites: definição, teoremas, limites laterais e no infinito\n- Continuidade de funções e Teorema do Valor Intermediário\n- Derivadas: conceito, regras de derivação e Regra da Cadeia\n- Aplicações de derivadas: taxas de variação, máximos e mínimos\n- Construção de gráficos com auxílio de derivadas\n- Integrais definidas e indefinidas\n- Técnicas de integração e aplicações (áreas e volumes)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- GUIDORIZZI, H. L. Um Curso de Cálculo – v.1. 5ª ed. Rio de Janeiro: LTC, 2002.\n- LEITHOLD, L. O Cálculo com Geometria Analítica – v.1. 3ª ed. São Paulo: Harbra, 1994.\n- THOMAS, G. B. Cálculo – v.1. 11ª ed. São Paulo: Pearson Addison Wesley, 2009.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- ANTON, H. Cálculo – v.1. 8ª ed. Porto Alegre: Bookman, 2007.\n- LARSON, R. E.; HOSTETLER, R. P.; EDWARDS, B. H. Cálculo com Aplicações. 4ª ed. Rio de Janeiro: LTC, 1998.\n- STEWART, J. Cálculo – v.1. 7ª ed. São Paulo: Cengage Learning, 2013.",
  "s1-fisica": "# Física Aplicada\n\nConceitos fundamentais de mecânica, fluidos, termodinâmica e ondas com aplicações diretas ao saneamento ambiental e à engenharia hidráulica.\n\n## Tópicos de Estudo\n\n- Cinemática: movimento retilíneo, circular e lançamentos\n- Dinâmica: Leis de Newton e suas aplicações\n- Trabalho, energia cinética e potencial\n- Momento linear e colisões\n- Estática e equilíbrio de corpos rígidos\n- Mecânica dos fluidos: pressão, empuxo e escoamento\n- Termodinâmica: calor, temperatura e leis da termodinâmica\n- Ondas mecânicas e acústica ambiental\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- HALLIDAY, D.; RESNICK, R.; WALKER, J. Fundamentos de Física – v.1 Mecânica. 8ª ed. Rio de Janeiro: LTC, 2009.\n- HALLIDAY, D.; RESNICK, R.; WALKER, J. Fundamentos de Física – v.2 Gravitação, Ondas e Termodinâmica. 8ª ed. Rio de Janeiro: LTC, 2009.\n- NUSSENZVEIG, H. M. Curso de Física Básica – v.1 Mecânica. 4ª ed. São Paulo: Edgard Blücher, 2002.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- SEARS, F. W.; ZEMANSKY, M. W. Física – v.2 Termodinâmica e Ondas. 12ª ed. São Paulo: Pearson, 2009.\n- TIPLER, P. A.; MOSCA, G. Física para Cientistas e Engenheiros – v.1. 6ª ed. Rio de Janeiro: LTC, 2009.",
  "s1-informatica": "# Informática\n\nFundamentos de informática, ferramentas de escritório, planilhas eletrônicas e uso de tecnologias digitais para suporte técnico em saneamento ambiental.\n\n## Tópicos de Estudo\n\n- Hardware e software: conceitos fundamentais\n- Sistemas operacionais: Windows e Linux básico\n- Processadores de texto: formatação técnica (Word/LibreOffice)\n- Planilhas eletrônicas: fórmulas, gráficos e análise de dados (Excel)\n- Apresentações técnicas (PowerPoint/Impress)\n- Internet: pesquisa, segurança digital e ética\n- Banco de dados: conceitos básicos\n- Software técnico aplicado ao saneamento (AutoCAD, EPANET)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- MANZANO, J. A. N. G.; MANZANO, M. I. N. G. Estudo Dirigido de Microsoft Office 365. São Paulo: Érica, 2017.\n- CAPRON, H. L.; JOHNSON, J. A. Introdução à Informática. 8ª ed. São Paulo: Pearson, 2004.\n- NORTON, P. Introdução à Informática. São Paulo: Makron Books, 1997.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- VELLOSO, F. de C. Informática: Conceitos Básicos. 9ª ed. Rio de Janeiro: Elsevier, 2014.\n- TANENBAUM, A. S. Redes de Computadores. 5ª ed. São Paulo: Pearson, 2011.",
  "s1-ingles": "# Inglês Instrumental\n\nLeitura e compreensão de textos técnicos e científicos em inglês na área de saneamento ambiental, com foco em vocabulário específico e estratégias de leitura.\n\n## Tópicos de Estudo\n\n- Estratégias de leitura: skimming e scanning\n- Vocabulário técnico de saneamento ambiental em inglês\n- Estruturas gramaticais essenciais para leitura técnica\n- Compreensão de textos científicos e normas internacionais\n- Leitura de manuais, relatórios e artigos técnicos\n- Uso de dicionários técnicos bilíngues\n- Interpretação de gráficos, tabelas e figuras em inglês\n- Tradução técnica aplicada ao saneamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- SOUZA, A. G. F. et al. Leitura em Língua Inglesa: Uma Abordagem Instrumental. São Paulo: Disal, 2005.\n- MURPHY, R. English Grammar in Use. 4ª ed. Cambridge: Cambridge University Press, 2012.\n- HUTCHINSON, T.; WATERS, A. English for Specific Purposes. Cambridge: Cambridge University Press, 1987.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- GLENDINNING, E. H.; McEWAN, J. Basic English for Computing. Oxford: Oxford University Press, 2002.\n- OXFORD. Oxford Wordpower Dictionary. Oxford: Oxford University Press, 2006.",
  "s1-quimica": "# Química Aplicada\n\nFundamentos de química geral, equilíbrio iônico, termoquímica, oxi-redução, estrutura e qualidade da água, e química ambiental aplicada ao saneamento.\n\n## Tópicos de Estudo\n\n- Fundamentos de química geral e estrutura atômica\n- Tabela periódica e ligações químicas\n- Funções inorgânicas: ácidos, bases, sais e óxidos\n- Estequiometria e cálculos químicos\n- Equilíbrio iônico da água e pH\n- Termoquímica e cinética química\n- Equilíbrio de oxi-redução\n- Estrutura e qualidades físico-químicas da água\n- Noções de química ambiental\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BAIRD, C. Química Ambiental. 2ª ed. Porto Alegre: Bookman, 2004.\n- BRADY, J. E.; HUMISTON, G. E. Química Geral – v.1. 2ª ed. Rio de Janeiro: LTC, 1986.\n- SPIRO, T. G.; STIGLIANI, W. M. Química Ambiental. 2ª ed. São Paulo: Pearson Prentice Hall, 2009.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- ROCHA, J. C.; ROSA, A. H.; CARDOSO, A. A. Introdução à Química Ambiental. 2ª ed. Porto Alegre: Bookman, 2009.\n- KOTZ, J. C.; TREICHEL, P. M. Química Geral e Reações Químicas – v.1. São Paulo: Cengage Learning, 2014.",
  "s1-sociologia": "# Sociologia do Trabalho\n\nAnálise das relações de trabalho, organização social, ética profissional e dinâmicas do mercado de trabalho na área de saneamento e meio ambiente.\n\n## Tópicos de Estudo\n\n- Conceitos básicos de sociologia: sociedade, cultura e instituições\n- Evolução histórica do trabalho e relações trabalhistas\n- Organização do trabalho: taylorismo, fordismo e toyotismo\n- Mercado de trabalho em saneamento ambiental no Brasil\n- Ética profissional e responsabilidade social\n- Direitos trabalhistas e legislação do trabalho (CLT)\n- Movimentos sociais e políticas públicas de saneamento\n- Gênero, diversidade e inclusão no ambiente de trabalho\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ANTUNES, R. Os Sentidos do Trabalho: Ensaio sobre a Afirmação e a Negação do Trabalho. 2ª ed. São Paulo: Boitempo, 2009.\n- GIDDENS, A. Sociologia. 6ª ed. Porto Alegre: Penso, 2012.\n- HARVEY, D. Condição Pós-Moderna. 24ª ed. São Paulo: Loyola, 2013.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- CASTEL, R. As Metamorfoses da Questão Social. 9ª ed. Petrópolis: Vozes, 2010.\n- CATTANI, A. D. (org.). Trabalho e Tecnologia: Dicionário Crítico. 4ª ed. Porto Alegre: UFRGS, 2002.",
  "s2-desenho-topo": "# Desenho Técnico e Topográfico\n\nTécnicas de desenho técnico e topográfico, leitura de plantas, representação de redes de saneamento e utilização de ferramentas CAD.\n\n## Tópicos de Estudo\n\n- Normas técnicas de desenho (ABNT NBR): escalas, legendas e convenções\n- Projeções ortogonais: vistas, cortes e seções\n- Perspectivas isométricas e cavaleiras\n- Representação de redes de água e esgoto em plantas\n- Noções de topografia: conceitos básicos e instrumentos\n- Levantamento topográfico planimétrico e altimétrico\n- Perfis longitudinais e transversais\n- Introdução ao AutoCAD: comandos básicos de 2D\n- Elaboração e leitura de projetos de saneamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- FRENCH, T. E.; VIERCK, C. J. Desenho Técnico e Tecnologia Gráfica. 8ª ed. São Paulo: Globo, 2005.\n- SILVA, A. et al. Desenho Técnico Moderno. 4ª ed. Rio de Janeiro: LTC, 2006.\n- BORGES, A. C. Topografia. 2 v. São Paulo: Edgard Blücher, 2004.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- GIESECKE, F. E. et al. Comunicação Gráfica Moderna. Porto Alegre: Bookman, 2002.\n- COMASTRI, J. A.; TULER, J. C. Topografia: Altimetria. 3ª ed. Viçosa: UFV, 2005.",
  "s2-ecologia": "# Ecologia Aplicada\n\nPrincípios ecológicos fundamentais, dinâmica de populações, ecossistemas aquáticos e terrestres, impactos ambientais e sustentabilidade.\n\n## Tópicos de Estudo\n\n- Ecologia de populações: crescimento, dinâmica e regulação\n- Comunidades ecológicas: estrutura, sucessão e diversidade\n- Ecossistemas: fluxo de energia e ciclos biogeoquímicos\n- Biomas brasileiros e sua importância para o saneamento\n- Ecologia aquática: rios, lagos, estuários e zonas costeiras\n- Eutrofização e autodepuração de corpos d'água\n- Impactos ambientais: tipos, avaliação e mitigação\n- Desenvolvimento sustentável e serviços ecossistêmicos\n- Legislação ambiental e áreas de preservação\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ODUM, E. P.; BARRETT, G. W. Fundamentos de Ecologia. São Paulo: Thomson, 2008.\n- RICKLEFS, R. E. A Economia da Natureza. 6ª ed. Rio de Janeiro: Guanabara Koogan, 2010.\n- TOWNSEND, C. R.; BEGON, M.; HARPER, J. L. Fundamentos em Ecologia. 3ª ed. Porto Alegre: Artmed, 2010.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BRAGA, B. et al. Introdução à Engenharia Ambiental. 2ª ed. São Paulo: Pearson, 2005.\n- MILLER JR., G. T. Ciência Ambiental. 11ª ed. São Paulo: Thomson, 2007.",
  "s2-estatistica": "# Estatística\n\nMétodos estatísticos descritivos e inferenciais aplicados à análise de dados ambientais, controle de qualidade da água e interpretação de resultados em saneamento.\n\n## Tópicos de Estudo\n\n- Estatística descritiva: medidas de tendência central e dispersão\n- Distribuições de frequência e representações gráficas\n- Probabilidade: conceitos, teoremas e distribuições\n- Distribuição normal, binomial e de Poisson\n- Amostragem: tipos e métodos\n- Intervalos de confiança e testes de hipóteses\n- Correlação e regressão linear simples\n- Controle estatístico de qualidade em análises de água\n- Uso de softwares estatísticos (Excel, R básico)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BUSSAB, W. O.; MORETTIN, P. A. Estatística Básica. 8ª ed. São Paulo: Saraiva, 2013.\n- MONTGOMERY, D. C.; RUNGER, G. C. Estatística Aplicada e Probabilidade para Engenheiros. 6ª ed. Rio de Janeiro: LTC, 2016.\n- TRIOLA, M. F. Introdução à Estatística. 12ª ed. Rio de Janeiro: LTC, 2017.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- DEVORE, J. L. Probabilidade e Estatística para Engenharia e Ciências. 8ª ed. São Paulo: Cengage Learning, 2014.\n- WALPOLE, R. E. et al. Probabilidade e Estatística para Engenharia e Ciências. 8ª ed. São Paulo: Pearson, 2009.",
  "s2-hidraulica": "# Hidráulica e Hidrotécnica\n\nPrincípios de hidrostática, hidrodinâmica, escoamento em tubulações e canais abertos, com aplicações em sistemas de abastecimento de água e esgotamento sanitário.\n\n## Tópicos de Estudo\n\n- Hidrostática: pressão, empuxo e superfícies imersas\n- Hidrodinâmica: equação da continuidade e Bernoulli\n- Escoamento em tubulações: regime laminar e turbulento\n- Perda de carga: Darcy-Weisbach e Hazen-Williams\n- Escoamento em canais abertos: classificação e perfis\n- Medidores de vazão: vertedores, calhas Parshall e orifícios\n- Redes de distribuição de água: dimensionamento básico\n- Bombas hidráulicas: tipos, curva e ponto de operação\n- Golpe de aríete e proteção de redes\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- AZEVEDO NETTO, J. M. et al. Manual de Hidráulica. 9ª ed. São Paulo: Edgard Blücher, 2015.\n- PORTO, R. M. Hidráulica Básica. 4ª ed. São Carlos: EESC-USP, 2006.\n- NETTO, A.; FERNANDEZ, M. F. Manual de Hidráulica. 8ª ed. São Paulo: Edgard Blücher, 1998.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BAPTISTA, M. B.; LARA, M. Fundamentos de Engenharia Hidráulica. 3ª ed. Belo Horizonte: UFMG, 2010.\n- WHITE, F. M. Mecânica dos Fluidos. 6ª ed. Porto Alegre: McGraw-Hill, 2010.",
  "s2-hidrobiologia": "# Hidrobiologia\n\nEstudo dos organismos aquáticos, sua relação com o ambiente, bioindicadores de qualidade da água e ecologia de ecossistemas hídricos.\n\n## Tópicos de Estudo\n\n- Características físico-químicas dos ambientes aquáticos\n- Organismos aquáticos: fitoplâncton, zooplâncton e bentos\n- Macrófitas aquáticas e algas: diversidade e ecologia\n- Comunidades de peixes em ambientes lóticos e lênticos\n- Bioindicadores de qualidade da água\n- Índice biótico e índices de diversidade\n- Ecologia de rios: regime hidrológico e biodiversidade\n- Ecossistemas lênticos: lagos, lagoas e reservatórios\n- Florações de cianobactérias e riscos à saúde pública\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ESTEVES, F. A. Fundamentos de Limnologia. 3ª ed. Rio de Janeiro: Interciência, 2011.\n- TUNDISI, J. G.; TUNDISI, T. M. Limnologia. São Paulo: Oficina de Textos, 2008.\n- WETZEL, R. G. Limnology: Lake and River Ecosystems. 3ª ed. San Diego: Academic Press, 2001.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BICUDO, C. E. M.; MENEZES, M. Gêneros de Algas de Águas Continentais do Brasil. 2ª ed. São Carlos: RiMa, 2006.\n- CALLISTO, M.; MORETTI, M.; GOULART, M. Macroinvertebrados Bentônicos como Ferramenta para Avaliar a Saúde de Riachos. Belo Horizonte: UFMG, 2001.",
  "s2-quimica-analitica": "# Química Analítica Aplicada\n\nTécnicas de análise química qualitativa e quantitativa aplicadas ao controle de qualidade da água, efluentes e amostras ambientais.\n\n## Tópicos de Estudo\n\n- Fundamentos de análise química qualitativa\n- Análise quantitativa: gravimetria e volumetria\n- Titulações: ácido-base, complexometria e óxido-redução\n- Espectrofotometria UV-Vis aplicada à análise de água\n- Cromatografia: princípios e aplicações ambientais\n- Preparo de soluções e calibração de equipamentos\n- Controle de qualidade analítico e incerteza de medição\n- Parâmetros físico-químicos da água: pH, turbidez, DBO, DQO\n- Análise de metais pesados em amostras ambientais\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- HARRIS, D. C. Análise Química Quantitativa. 8ª ed. Rio de Janeiro: LTC, 2012.\n- SKOOG, D. A. et al. Fundamentos de Química Analítica. 9ª ed. São Paulo: Cengage Learning, 2015.\n- VOGEL, A. I. Química Analítica Qualitativa. 5ª ed. São Paulo: Mestre Jou, 1981.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- APHA; AWWA; WEF. Standard Methods for the Examination of Water and Wastewater. 23ª ed. Washington: APHA, 2017.\n- AMERICAN PUBLIC HEALTH ASSOCIATION. Métodos Padrão para Exame de Água e Esgoto. São Paulo: APHA, 2005.",
  "s3-analise-aguas": "# Análise de Águas e Efluentes\n\nMetodologias analíticas para caracterização físico-química e microbiológica de águas naturais, de abastecimento e efluentes industriais e domésticos.\n\n## Tópicos de Estudo\n\n- Amostragem de água e efluentes: técnicas e preservação\n- Parâmetros físicos: cor, turbidez, temperatura e odor\n- Parâmetros químicos: pH, alcalinidade, dureza, cloretos e nitrogênio\n- Oxigênio dissolvido (OD) e demanda bioquímica de oxigênio (DBO)\n- Demanda química de oxigênio (DQO) e sólidos\n- Nutrientes: fósforo e nitrogênio total – métodos analíticos\n- Análise microbiológica: coliformes totais e termotolerantes\n- Metais pesados e micropoluentes: técnicas de determinação\n- Interpretação de resultados conforme Resolução CONAMA 357/05 e Portaria 2914/11\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- APHA; AWWA; WEF. Standard Methods for the Examination of Water and Wastewater. 23ª ed. Washington: APHA, 2017.\n- CETESB. Guia Nacional de Coleta e Preservação de Amostras. São Paulo: CETESB, 2011.\n- BRASIL. Resolução CONAMA nº 357/2005 e nº 430/2011. Brasília: MMA, 2005.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- FUNASA. Manual Prático de Análise de Água. 4ª ed. Brasília: FUNASA, 2013.\n- SILVA, R. C. A.; NOUR, E. A. A. Análise de Água: Roteiro de Aulas Práticas. Campinas: UNICAMP, 2002.",
  "s3-bombas": "# Bombas, Máquinas e Equipamentos\n\nPrincípios de funcionamento, seleção, instalação e manutenção de bombas hidráulicas, compressores e equipamentos eletromecânicos utilizados em sistemas de saneamento.\n\n## Tópicos de Estudo\n\n- Classificação de máquinas hidráulicas: centrífugas e volumétricas\n- Curvas características de bombas: Q×H, Q×η e Q×P\n- Ponto de operação e seleção de bombas\n- Instalações hidráulicas de bombeamento: NPSH e cavitação\n- Bombas em série e em paralelo\n- Motores elétricos: tipos, eficiência e acionamento\n- Variadores de frequência (inversor de frequência) e eficiência energética\n- Manutenção preventiva e corretiva de conjuntos motor-bomba\n- Estações elevatórias de água e esgoto\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- AZEVEDO NETTO, J. M. et al. Manual de Hidráulica. 9ª ed. São Paulo: Edgard Blücher, 2015.\n- MACINTYRE, A. J. Bombas e Instalações de Bombeamento. 2ª ed. Rio de Janeiro: LTC, 1997.\n- WEG. Manual de Motores Elétricos. Jaraguá do Sul: WEG Indústrias, 2016.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- HENN, E. A. L. Máquinas de Fluido. 2ª ed. Santa Maria: UFSM, 2006.\n- KAPLAN, S. Bombeamento: Manual Prático. São Paulo: Hemus, 2004.",
  "s3-hidrogeologia": "# Hidrogeologia\n\nOcorrência e movimento das águas subterrâneas, aquíferos, captação de poços e proteção de mananciais subterrâneos no contexto do abastecimento de água.\n\n## Tópicos de Estudo\n\n- Porosidade e permeabilidade de solos e rochas\n- Tipos de aquíferos: livres, confinados e semiconfinados\n- Lei de Darcy e escoamento em meios porosos\n- Recarga de aquíferos e zonas de proteção\n- Poços de abastecimento: projeto e dimensionamento\n- Ensaios de bombeamento e interpretação\n- Vulnerabilidade e contaminação de aquíferos\n- Proteção de mananciais subterrâneos: legislação\n- Sistemas aquíferos do Brasil: Guarani e outros\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- FEITOSA, F. A. C. et al. (org.). Hidrogeologia: Conceitos e Aplicações. 3ª ed. Rio de Janeiro: CPRM/LABHID, 2008.\n- FREEZE, R. A.; CHERRY, J. A. Groundwater. New Jersey: Prentice Hall, 1979.\n- REBOUÇAS, A. C.; BRAGA, B.; TUNDISI, J. G. Águas Doces no Brasil. 3ª ed. São Paulo: Escrituras, 2006.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- HEATH, R. C. Basic Ground-Water Hydrology. USGS Water Supply Paper 2220. 1983.\n- BRASIL. Lei nº 9.433/1997: Política Nacional de Recursos Hídricos. Brasília, 1997.",
  "s3-hidrologia": "# Hidrologia Aplicada\n\nCiclo hidrológico, precipitação, escoamento superficial, infiltração e análise de bacias hidrográficas com aplicações ao projeto e operação de sistemas de saneamento.\n\n## Tópicos de Estudo\n\n- Ciclo hidrológico: componentes e balanço hídrico\n- Precipitação: medição, análise e distribuição temporal\n- Evapotranspiração: métodos de estimativa\n- Infiltração: modelos de Horton, Green-Ampt e Philip\n- Escoamento superficial: hidrograma e tempo de concentração\n- Análise de bacias hidrográficas: parâmetros morfométricos\n- Cheias: estimativa de vazões máximas (métodos racional e SCS)\n- Qualidade da água em bacias hidrográficas\n- Risco hidrológico e enchentes urbanas\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- TUCCI, C. E. M. (org.). Hidrologia: Ciência e Aplicação. 4ª ed. Porto Alegre: ABRH/UFRGS, 2009.\n- PINTO, N. L. S. et al. Hidrologia Básica. São Paulo: Edgard Blücher, 1976.\n- GARCEZ, L. N.; ALVAREZ, G. A. Hidrologia. 2ª ed. São Paulo: Edgard Blücher, 2013.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- CHOW, V. T.; MAIDMENT, D. R.; MAYS, L. W. Applied Hydrology. New York: McGraw-Hill, 1988.\n- TUNDISI, J. G. Água no Século XXI. São Carlos: RiMa, 2003.",
  "s3-higiene": "# Higiene e Segurança do Trabalho\n\nPrevenção de acidentes, riscos ocupacionais em obras e laboratórios de saneamento, normas regulamentadoras e equipamentos de proteção individual e coletiva.\n\n## Tópicos de Estudo\n\n- Acidentes do trabalho: conceito, classificação e prevenção\n- Riscos ocupacionais: físicos, químicos, biológicos, ergonômicos e mecânicos\n- CIPA – Comissão Interna de Prevenção de Acidentes (NR-5)\n- EPI e EPC: seleção, uso e manutenção\n- NR-6 (EPI), NR-10 (Instalações elétricas), NR-18 (Construção civil)\n- NR-33: Trabalhos em espaços confinados (essencial em saneamento)\n- Higiene industrial: avaliação de agentes nocivos\n- Sinalização de segurança e rotas de fuga\n- Primeiros socorros e plano de emergência\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Normas Regulamentadoras do Ministério do Trabalho e Emprego (NRs). Brasília: MTE, 2023.\n- SALIBA, T. M. Curso Básico de Segurança e Higiene Ocupacional. 5ª ed. São Paulo: LTr, 2013.\n- CARDELLA, B. Segurança no Trabalho e Prevenção de Acidentes. São Paulo: Atlas, 1999.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- GONÇALVES, E. A. Manual de Segurança e Saúde no Trabalho. 5ª ed. São Paulo: LTr, 2012.\n- FUNDACENTRO. Segurança e Medicina do Trabalho. São Paulo: Fundacentro, 2010.",
  "s3-metodologia": "# Metodologia do Trabalho Científico\n\nFundamentos da pesquisa científica, métodos de investigação, normas ABNT para trabalhos acadêmicos e elaboração de projetos de pesquisa em saneamento ambiental.\n\n## Tópicos de Estudo\n\n- Ciência: conceito, classificação e produção do conhecimento\n- Métodos científicos: indutivo, dedutivo e hipotético-dedutivo\n- Tipos de pesquisa: exploratória, descritiva e explicativa\n- Pesquisa bibliográfica: bases de dados (Scielo, Capes, Google Scholar)\n- Elaboração de projetos de pesquisa\n- Normas ABNT: NBR 6023, NBR 14724, NBR 6024, NBR 6028\n- Estrutura de trabalhos acadêmicos: TCC, artigos e relatórios\n- Plagiato e ética na pesquisa científica\n- Apresentação oral de trabalhos científicos\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- LAKATOS, E. M.; MARCONI, M. A. Fundamentos de Metodologia Científica. 7ª ed. São Paulo: Atlas, 2010.\n- GIL, A. C. Como Elaborar Projetos de Pesquisa. 5ª ed. São Paulo: Atlas, 2010.\n- SEVERINO, A. J. Metodologia do Trabalho Científico. 23ª ed. São Paulo: Cortez, 2007.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- ABNT. NBR 14724: Trabalhos Acadêmicos. Rio de Janeiro: ABNT, 2011.\n- DEMO, P. Pesquisa e Construção do Conhecimento. 7ª ed. Rio de Janeiro: Tempo Brasileiro, 2009.",
  "s3-topografia": "# Topografia (Cartografia e GPS)\n\nTécnicas avançadas de levantamento topográfico, cartografia digital, uso de GPS e sistemas de informações geográficas aplicados ao planejamento de obras de saneamento.\n\n## Tópicos de Estudo\n\n- Conceitos de geodésia e datum geodésico (SIRGAS 2000)\n- Sistemas de coordenadas: geográfico e plano\n- Levantamento planimétrico: poligonal aberta e fechada\n- Levantamento altimétrico: nivelamento geométrico e trigonométrico\n- Curvas de nível e representação do relevo\n- Global Navigation Satellite Systems (GPS/GNSS): princípios e uso\n- Cartografia: escala, projeções e leitura de cartas topográficas\n- Introdução aos Sistemas de Informação Geográfica (SIG/GIS)\n- Locação de obras de saneamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BORGES, A. C. Topografia. v.1 e v.2. São Paulo: Edgard Blücher, 2004.\n- CASACA, J. M. et al. Topografia Geral. 4ª ed. Rio de Janeiro: LTC, 2007.\n- FITZ, P. R. Cartografia Básica. São Paulo: Oficina de Textos, 2008.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- IBGE. Noções Básicas de Cartografia. Rio de Janeiro: IBGE, 1999.\n- ESRI. Introduction to GIS. Redlands: ESRI Press, 2016.",
  "s4-abastecimento": "# Sistema de Abastecimento – Tratamento de Água\n\nProjeto e operação de sistemas de captação, adução, reservação e tratamento de água para abastecimento público, atendendo aos padrões de potabilidade.\n\n## Tópicos de Estudo\n\n- Mananciais: tipos, proteção e enquadramento (CONAMA 357/05)\n- Captação de água superficial e subterrânea\n- Adutoras: dimensionamento e materiais\n- Reservatórios de distribuição: tipos e dimensionamento\n- Redes de distribuição: dimensionamento e pressão\n- Estação de Tratamento de Água (ETA): etapas do tratamento\n- Coagulação, floculação, sedimentação e filtração\n- Desinfecção: cloração, ozonização e UV\n- Portaria GM/MS 888/2021: padrão de potabilidade da água\n- Fluoretação e controle de qualidade na ETA\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- HELLER, L.; PÁDUA, V. L. (org.). Abastecimento de Água para Consumo Humano. 2ª ed. Belo Horizonte: UFMG, 2010.\n- DI BERNARDO, L.; DANTAS, A. D. B. Métodos e Técnicas de Tratamento de Água. 2ª ed. São Carlos: RiMa, 2005.\n- TSUTIYA, M. T. Abastecimento de Água. 4ª ed. São Paulo: POLI/USP, 2006.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- FUNASA. Manual de Saneamento. 4ª ed. Brasília: FUNASA, 2015.\n- BRASIL. Portaria GM/MS nº 888/2021 – Padrão de Potabilidade. Brasília: MS, 2021.",
  "s4-acudes": "# Projeto, Construção e Operação de Açudes\n\nDimensionamento, construção e operação de barragens de terra e açudes, com ênfase no contexto semiárido e no armazenamento de água para múltiplos usos.\n\n## Tópicos de Estudo\n\n- Tipos de barragens: terra, enrocamento e concreto\n- Estudo de viabilidade e seleção de local para barragens\n- Hidrologia de barragens: curva cota-volume-área\n- Dimensionamento do vertedor e da bacia de dissipação\n- Construção de barragens de terra: compactação e controle\n- Instrumentação de barragens: piezômetros e marcos\n- Segurança de barragens: Lei nº 12.334/2010 (PNSB)\n- Operação e manutenção de açudes\n- Convivência com o semiárido: cisternas e barragens subterrâneas\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- PONCE, V. M. Engineering Hydrology: Principles and Practices. San Diego State University, 1994.\n- CHAUDHRY, M. H. Open-Channel Hydraulics. 2ª ed. New York: Springer, 2008.\n- CEARÁ. COGERH. Manual de Operação e Manutenção de Açudes. Fortaleza: COGERH, 2009.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BRASIL. Lei nº 12.334/2010 – Política Nacional de Segurança de Barragens. Brasília, 2010.\n- DNOCS. Manual de Pequenas Barragens. Fortaleza: DNOCS, 2011.",
  "s4-construcao": "# Construção e Gerenciamento de Obras em Saneamento\n\nTécnicas de construção civil aplicadas a obras de saneamento, gerenciamento de projetos, orçamentação, cronograma e fiscalização de obras.\n\n## Tópicos de Estudo\n\n- Materiais de construção em saneamento: tubulações e conexões\n- Escavação, escoramento e reaterro de valas\n- Assentamento de tubulações: água, esgoto e drenagem\n- Obras de arte: poços, reservatórios e estações de tratamento\n- Orçamentação de obras de saneamento: composição de custos\n- Gerenciamento de projetos: PMBOK básico, cronograma e EAP\n- Contratos de obras: licitação e Lei 14.133/2021\n- Fiscalização de obras e controle de qualidade\n- Segurança em canteiros de obras de saneamento (NR-18)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- YAZIGI, W. A Técnica de Edificar. 12ª ed. São Paulo: SindusCon/Pini, 2013.\n- ÁVILA, A. V.; LIBRELOTTO, L. I.; LOPES, O. C. Orçamento na Construção Civil. Florianópolis: UFSC, 2003.\n- BRASIL. Lei nº 14.133/2021 – Lei de Licitações e Contratos Administrativos. Brasília, 2021.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- PMI. Um Guia do Conhecimento em Gerenciamento de Projetos (PMBOK). 6ª ed. São Paulo: PMI, 2017.\n- MATTOS, A. D. Como Preparar Orçamentos de Obras. São Paulo: Pini, 2006.",
  "s4-drenagem": "# Sistema de Drenagem Urbana\n\nPlanejamento, projeto e gestão de sistemas de drenagem pluvial urbana, controle de inundações e soluções baseadas na natureza (SBN).\n\n## Tópicos de Estudo\n\n- Problemas de drenagem urbana: impermeabilização e inundações\n- Ciclo hidrológico urbano: precipitação, escoamento e infiltração\n- Dimensionamento de redes de drenagem: método racional\n- Sarjetas, bocas-de-lobo e coletores de drenagem pluvial\n- Bacias de detenção e retenção: dimensionamento\n- Técnicas de drenagem sustentável: jardins de chuva, biovaletas e pavimentos permeáveis\n- Soluções baseadas na Natureza (SBN) para drenagem\n- Plano Diretor de Drenagem Urbana (PDDU)\n- Mapeamento de áreas de risco e alertas de inundação\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- TUCCI, C. E. M. Águas Urbanas. Estudos Avançados. São Paulo: USP, 2008.\n- BOTELHO, M. H. C. Águas de Chuva: Engenharia das Águas Pluviais nas Cidades. 3ª ed. São Paulo: Edgard Blücher, 2011.\n- POMPÊO, C. A. Drenagem Urbana Sustentável. Florianópolis: UFSC, 2000.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- CANHOLI, A. P. Drenagem Urbana e Controle de Enchentes. 2ª ed. São Paulo: Oficina de Textos, 2014.\n- BRASIL. Plano Nacional de Saneamento Básico (PLANSAB). Brasília: MCidades, 2013.",
  "s4-esgoto": "# Sistema de Esgotamento Sanitário\n\nConcepção, projeto, operação e manutenção de sistemas de coleta, transporte e afastamento de esgotos domésticos e industriais.\n\n## Tópicos de Estudo\n\n- Geração de esgoto: contribuição per capita e coeficientes\n- Coletores de esgoto: dimensionamento e materiais (NBR 9649)\n- Poços de visita, caixas de inspeção e ramais prediais\n- Estações elevatórias de esgoto bruto\n- Ligações prediais e redes coletoras secundárias\n- Sistemas condominiais de esgoto: princípios e vantagens\n- Fossas sépticas e disposição de efluentes (NBR 7229 e 13969)\n- Emissários terrestres e subaquáticos\n- Operação e manutenção de redes de esgoto\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- TSUTIYA, M. T.; ALEM SOBRINHO, P. (ed.). Coleta e Transporte de Esgoto Sanitário. 3ª ed. São Paulo: POLI/USP, 2011.\n- JORDÃO, E. P.; PESSÔA, C. A. Tratamento de Esgotos Domésticos. 7ª ed. Rio de Janeiro: SEGRAC, 2014.\n- ABNT. NBR 9649: Projetos de Redes Coletoras de Esgoto Sanitário. Rio de Janeiro: ABNT, 1986.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- NUVOLARI, A. (coord.). Esgoto Sanitário. São Paulo: Edgard Blücher, 2003.\n- FUNASA. Manual de Saneamento. 4ª ed. Brasília: FUNASA, 2015.",
  "s4-instalacoes": "# Instalações Hidro-Sanitárias\n\nProjeto e dimensionamento de sistemas prediais de água fria, água quente, esgoto sanitário, ventilação e águas pluviais conforme normas ABNT.\n\n## Tópicos de Estudo\n\n- Sistemas prediais de água fria: projeto e dimensionamento (NBR 5626)\n- Reservatórios prediais: inferior e superior – dimensionamento\n- Instalações de água quente: aquecedores solar, a gás e elétrico\n- Sistemas prediais de esgoto sanitário (NBR 8160)\n- Sistema de ventilação de redes prediais de esgoto\n- Instalações de águas pluviais: calhas, condutores e caixas (NBR 10844)\n- Caixas de gordura e separadores de gordura\n- Pressão e vazão em instalações prediais\n- Aprovação de projetos e interface com a concessionária\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- CREDER, H. Instalações Hidráulicas e Sanitárias. 6ª ed. Rio de Janeiro: LTC, 2006.\n- ABNT. NBR 5626: Instalação Predial de Água Fria. Rio de Janeiro: ABNT, 1998.\n- ABNT. NBR 8160: Sistemas Prediais de Esgoto Sanitário. Rio de Janeiro: ABNT, 1999.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- ILHA, M. S. O.; GONÇALVES, O. M. Instalações Hidráulicas Prediais. Campinas: UNICAMP, 1991.\n- MACINTYRE, A. J. Instalações Hidráulicas Prediais e Industriais. 4ª ed. Rio de Janeiro: LTC, 2010.",
  "s4-legislacao": "# Legislação Ambiental Brasileira\n\nMarco legal do meio ambiente no Brasil: Constituição Federal, Código Florestal, política de recursos hídricos, saneamento básico e crimes ambientais.\n\n## Tópicos de Estudo\n\n- Constituição Federal de 1988: Art. 225 – Meio Ambiente\n- Política Nacional do Meio Ambiente (Lei nº 6.938/1981)\n- Sistema Nacional do Meio Ambiente (SISNAMA) e CONAMA\n- Licenciamento ambiental: EIA/RIMA (Resolução CONAMA 237/97)\n- Código Florestal Brasileiro (Lei nº 12.651/2012): APP e Reserva Legal\n- Política Nacional de Recursos Hídricos (Lei nº 9.433/1997)\n- Marco Legal do Saneamento Básico (Lei nº 14.026/2020)\n- Política Nacional de Resíduos Sólidos (Lei nº 12.305/2010)\n- Crimes ambientais (Lei nº 9.605/1998) e responsabilidade civil\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Constituição da República Federativa do Brasil. Brasília: Senado Federal, 1988.\n- BRASIL. Lei nº 6.938/1981 – Política Nacional do Meio Ambiente. Brasília, 1981.\n- BRASIL. Lei nº 12.305/2010 – Política Nacional de Resíduos Sólidos. Brasília, 2010.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- MACHADO, P. A. L. Direito Ambiental Brasileiro. 22ª ed. São Paulo: Malheiros, 2014.\n- SIRVINSKAS, L. P. Manual de Direito Ambiental. 16ª ed. São Paulo: Saraiva, 2018.",
  "s4-mecanica-solos": "# Mecânica dos Solos\n\nPropriedades físicas e mecânicas dos solos, classificação, compactação, permeabilidade e resistência aplicadas a obras de saneamento e infraestrutura hídrica.\n\n## Tópicos de Estudo\n\n- Origem e formação dos solos: mineralogia e estrutura\n- Índices físicos do solo: porosidade, índice de vazios e saturação\n- Granulometria e curva granulométrica (ABNT NBR 7181)\n- Plasticidade: limites de Atterberg e classificação dos solos\n- Compactação de solos: ensaio Proctor e curva de compactação\n- Permeabilidade: lei de Darcy e ensaios de permeabilidade\n- Pressão de terra e empuxo em estruturas de contenção\n- Resistência ao cisalhamento: ensaio de cisalhamento direto e triaxial\n- Fundações rasas em obras de saneamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- DAS, B. M. Fundamentos de Engenharia Geotécnica. 8ª ed. São Paulo: Cengage Learning, 2014.\n- CAPUTO, H. P. Mecânica dos Solos e suas Aplicações – v.1. 6ª ed. Rio de Janeiro: LTC, 2012.\n- PINTO, C. S. Curso Básico de Mecânica dos Solos. 3ª ed. São Paulo: Oficina de Textos, 2006.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- MASSAD, F. Obras de Terra. 2ª ed. São Paulo: Oficina de Textos, 2010.\n- VARGAS, M. Introdução à Mecânica dos Solos. São Paulo: McGraw-Hill do Brasil, 1977.",
  "s5-eia": "# Estudos de Impactos Ambientais\n\nMetodologia de avaliação de impactos ambientais, elaboração de EIA/RIMA, licenciamento ambiental e programas de controle e monitoramento ambiental.\n\n## Tópicos de Estudo\n\n- Avaliação de Impacto Ambiental (AIA): histórico e legislação\n- Resoluções CONAMA 001/86 e 237/97: EIA e RIMA\n- Diagnóstico ambiental: meios físico, biótico e socioeconômico\n- Identificação de impactos: matriz de Leopold e método de redes\n- Avaliação e valoração de impactos ambientais\n- Medidas mitigadoras, compensatórias e potencializadoras\n- Programa de Controle Ambiental (PCA) e Plano Básico Ambiental (PBA)\n- Relatório de Impacto ao Meio Ambiente (RIMA)\n- Audiências públicas e participação social no licenciamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Resolução CONAMA nº 001/1986 e nº 237/1997. Brasília: MMA, 1986/1997.\n- SÁNCHEZ, L. E. Avaliação de Impacto Ambiental: Conceitos e Métodos. 2ª ed. São Paulo: Oficina de Textos, 2013.\n- TOMMASI, L. R. Estudo de Impacto Ambiental. São Paulo: CETESB/Terragraph, 1994.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- FARIAS, T. Q. Aspectos Gerais da Política Nacional do Meio Ambiente. São Paulo: Malheiros, 2006.\n- BRAGA, B. et al. Introdução à Engenharia Ambiental. 2ª ed. São Paulo: Pearson, 2005.",
  "s5-empreendedorismo": "# Empreendedorismo\n\nFundamentos do empreendedorismo, elaboração de plano de negócios, inovação e oportunidades de atuação profissional no setor de saneamento ambiental.\n\n## Tópicos de Estudo\n\n- Conceito de empreendedorismo e perfil do empreendedor\n- Tipos de empresa: MEI, ME, EPP e sociedades\n- Análise de mercado e identificação de oportunidades\n- Canvas (Business Model Canvas): estrutura e aplicação\n- Plano de negócios: estrutura e elaboração\n- Inovação: tipos e modelos de inovação em saneamento\n- Marketing e estratégia de posicionamento\n- Financiamento: recursos próprios, investidores e linhas de crédito\n- Startups de saneamento e tecnologias ambientais\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- DORNELAS, J. C. A. Empreendedorismo: Transformando Ideias em Negócios. 7ª ed. São Paulo: Atlas, 2018.\n- OSTERWALDER, A.; PIGNEUR, Y. Business Model Generation. São Paulo: Alta Books, 2011.\n- CHIAVENATO, I. Empreendedorismo: Dando Asas ao Espírito Empreendedor. 4ª ed. São Paulo: Manole, 2012.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- DOLABELA, F. O Segredo de Luísa. São Paulo: Sextante, 2008.\n- BLANK, S.; DORF, B. Startup: Manual do Empreendedor. Rio de Janeiro: Alta Books, 2014.",
  "s5-gestao-ambiental": "# Gestão Ambiental\n\nSistemas de gestão ambiental, certificações ISO 14001, auditorias, indicadores de desempenho ambiental e responsabilidade corporativa no setor de saneamento.\n\n## Tópicos de Estudo\n\n- Sistemas de Gestão Ambiental (SGA): conceito e histórico\n- ISO 14001:2015: requisitos, implantação e certificação\n- Política ambiental e aspectos e impactos significativos\n- Auditoria ambiental: tipos, procedimentos e relatórios\n- Indicadores de desempenho ambiental (IDAs)\n- EMAS – Eco-Management and Audit Scheme\n- Responsabilidade social empresarial e ESG\n- Relatórios de sustentabilidade: GRI e ODS\n- Gestão ambiental em concessionárias de saneamento\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ABNT. NBR ISO 14001:2015 – Sistemas de Gestão Ambiental. Rio de Janeiro: ABNT, 2015.\n- BARBIERI, J. C. Gestão Ambiental Empresarial. 4ª ed. São Paulo: Saraiva, 2016.\n- SEIFFERT, M. E. B. ISO 14001 Sistemas de Gestão Ambiental. 4ª ed. São Paulo: Atlas, 2011.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- TACHIZAWA, T. Gestão Ambiental e Responsabilidade Social Corporativa. 7ª ed. São Paulo: Atlas, 2011.\n- GRI. Global Reporting Initiative: Sustainability Reporting Standards. Amsterdam: GRI, 2021.",
  "s5-meio-saude": "# Meio Ambiente e Saúde\n\nRelação entre determinantes ambientais e saúde humana, epidemiologia ambiental, doenças de veiculação hídrica e políticas de saúde ambiental.\n\n## Tópicos de Estudo\n\n- Determinantes sociais e ambientais da saúde (OMS)\n- Epidemiologia ambiental: conceitos e indicadores\n- Doenças de veiculação hídrica: cólera, febre tifoide, hepatite A\n- Doenças relacionadas a vetores: dengue, malária, esquistossomose\n- Saneamento e redução de morbimortalidade infantil\n- Toxicologia ambiental: agrotóxicos, metais pesados e poluentes orgânicos\n- Qualidade do ar e saúde respiratória\n- Saúde do trabalhador em saneamento\n- Vigilância epidemiológica e ambiental em saúde (SUS/VIGISUS)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- PHILIPPI JR., A. (ed.). Saneamento, Saúde e Ambiente. Barueri: Manole, 2005.\n- ROUQUAYROL, M. Z.; GURGEL, M. Epidemiologia e Saúde. 7ª ed. Rio de Janeiro: MedBook, 2013.\n- BRASIL. Ministério da Saúde. Guia de Vigilância em Saúde. 4ª ed. Brasília: MS, 2021.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- OPAS/OMS. Informe da Saúde no Mundo 2002. Brasília: OPAS, 2002.\n- FUNASA. Manual de Saneamento. 4ª ed. Brasília: FUNASA, 2015.",
  "s5-operacao": "# Operação e Manutenção de Sistemas de Água e Esgotos\n\nProcedimentos operacionais, manutenção preventiva e corretiva de sistemas de abastecimento de água e esgotamento sanitário, controle de perdas e qualidade.\n\n## Tópicos de Estudo\n\n- Operação de Estação de Tratamento de Água (ETA): rotinas e controle\n- Operação de Estação de Tratamento de Esgoto (ETE): rotinas e controle\n- Manutenção de redes de distribuição de água: detecção de vazamentos\n- Controle de perdas físicas e comerciais em sistemas de água\n- Operação e manutenção de estações elevatórias\n- Cloração em sistema: pontos de aplicação e monitoramento\n- Manutenção de redes coletoras de esgoto: desobstrução e inspeção\n- Plano de Segurança da Água (PSA) – OMS\n- Indicadores operacionais do SNIS para água e esgoto\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. SNIS – Diagnóstico dos Serviços de Água e Esgotos. Brasília: MDR, 2022.\n- FUNASA. Manual de Saneamento. 4ª ed. Brasília: FUNASA, 2015.\n- OMS. Manual para Desenvolvimento de Planos de Segurança da Água. Genebra: OMS, 2009.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- SABESP. Manual de Operação e Manutenção de Sistemas de Água. São Paulo: SABESP, 2015.\n- ANA. Guia de Avaliação de Sistemas de Abastecimento de Água. Brasília: ANA, 2019.",
  "s5-residuos-1": "# Gerenciamento de Resíduos Sólidos I\n\nClassificação, geração e acondicionamento de resíduos sólidos urbanos, coleta, transporte, triagem e políticas nacionais de resíduos sólidos.\n\n## Tópicos de Estudo\n\n- Classificação dos resíduos sólidos: ABNT NBR 10004:2004\n- Política Nacional de Resíduos Sólidos (Lei nº 12.305/2010)\n- Plano Nacional de Resíduos Sólidos (PLANARES)\n- Geração per capita e composição gravimétrica dos RSU\n- Acondicionamento e coleta de resíduos sólidos domiciliares\n- Coleta seletiva e logística reversa\n- Cooperativas de catadores e inclusão socioprodutiva\n- Estações de Transbordo e Triagem (ETT)\n- Indicadores de desempenho em resíduos sólidos (SNIS)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Lei nº 12.305/2010 – Política Nacional de Resíduos Sólidos. Brasília, 2010.\n- MONTEIRO, J. H. P. et al. Manual de Gerenciamento Integrado de Resíduos Sólidos. Rio de Janeiro: IBAM, 2001.\n- ABNT. NBR 10004:2004 – Resíduos Sólidos – Classificação. Rio de Janeiro: ABNT, 2004.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BRASIL. SNIS – Sistema Nacional de Informações sobre Saneamento. Brasília: MDR, 2022.\n- COMPROMISSO EMPRESARIAL PARA RECICLAGEM (CEMPRE). Lixo Municipal: Manual de Gerenciamento Integrado. São Paulo: CEMPRE, 2018.",
  "s5-trat-residuarias": "# Tratamento de Águas Residuárias\n\nProcessos físicos, químicos e biológicos de tratamento de esgotos domésticos e industriais, dimensionamento de estações de tratamento e gestão do lodo gerado.\n\n## Tópicos de Estudo\n\n- Caracterização de esgotos domésticos e industriais\n- Níveis de tratamento: preliminar, primário, secundário e terciário\n- Tratamento preliminar: grades, desarenadores e medidores de vazão\n- Tratamento primário: decantadores e flotadores\n- Tratamento biológico aeróbio: lodos ativados e variantes\n- Tratamento biológico anaeróbio: reatores UASB\n- Lagoas de estabilização: facultativa, anaeróbia e de maturação\n- Filtros biológicos e wetlands construídos\n- Tratamento e destinação do lodo de ETE\n- Dimensionamento de Estação de Tratamento de Esgoto (ETE)\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- JORDÃO, E. P.; PESSÔA, C. A. Tratamento de Esgotos Domésticos. 7ª ed. Rio de Janeiro: SEGRAC, 2014.\n- VON SPERLING, M. Introdução à Qualidade das Águas e ao Tratamento de Esgotos. 4ª ed. Belo Horizonte: UFMG, 2014.\n- METCALF & EDDY. Wastewater Engineering: Treatment and Resource Recovery. 5ª ed. New York: McGraw-Hill, 2014.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- CHERNICHARO, C. A. L. Reatores Anaeróbios. 2ª ed. Belo Horizonte: UFMG, 2007.\n- BRASIL. Resolução CONAMA nº 430/2011 – Condições de Lançamento de Efluentes. Brasília, 2011.",
  "s6-bacias": "# Gerenciamento das Bacias Hidrográficas\n\nPolítica de recursos hídricos, planos de bacia, comitês de bacia, cobrança pelo uso da água e instrumentos de gestão integrada dos recursos hídricos.\n\n## Tópicos de Estudo\n\n- Política Nacional de Recursos Hídricos (Lei 9.433/97): fundamentos e instrumentos\n- Domínio das águas: federais e estaduais\n- Plano de Recursos Hídricos: nacional, estadual e de bacia\n- Enquadramento dos corpos d'água (CONAMA 357/05)\n- Outorga de uso dos recursos hídricos\n- Cobrança pelo uso da água: metodologias e experiências\n- Comitês de Bacia Hidrográfica: composição e atribuições\n- Agências de Água e Sistema Nacional de Gerenciamento (SINGREH)\n- Gestão integrada de bacias transfronteiriças\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Lei nº 9.433/1997 – Política Nacional de Recursos Hídricos. Brasília, 1997.\n- LANNA, A. E. Gerenciamento de Bacia Hidrográfica. Brasília: IBAMA, 1995.\n- ANA. Conjuntura dos Recursos Hídricos no Brasil. Brasília: ANA, 2022.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- PORTO, M. F. A.; PORTO, R. L. Gestão de Bacias Hidrográficas. Estudos Avançados. São Paulo: USP, 2008.\n- BRAGA, B. et al. Pacto Federativo e Gestão das Águas. Estudos Avançados. São Paulo: USP, 2008.",
  "s6-informatica-san": "# Informática Aplicada a Saneamento Ambiental\n\nUso de softwares específicos para modelagem, simulação e gestão de sistemas de saneamento: EPANET, SWMM, SIG e sistemas de informação em saneamento.\n\n## Tópicos de Estudo\n\n- EPANET: modelagem de redes de distribuição de água\n- SWMM (Storm Water Management Model): simulação de drenagem\n- SIG aplicado ao saneamento: QGIS e ArcGIS básico\n- AutoCAD aplicado a projetos de saneamento\n- Planilhas avançadas para dimensionamento hidráulico (Excel VBA)\n- Sistemas de Informação em Saneamento: SNIS e outras plataformas\n- BIM (Building Information Modeling) em obras de saneamento\n- Banco de dados ambientais: consulta e análise\n- Sensoriamento remoto e imagens de satélite em gestão de bacias\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ROSSMAN, L. A. EPANET 2: Users Manual. Cincinnati: US EPA, 2000.\n- ROSSMAN, L. A. Storm Water Management Model (SWMM): Users Manual v5.1. Cincinnati: US EPA, 2015.\n- LONGLEY, P. A. et al. Sistemas e Ciência da Informação Geográfica. 3ª ed. Porto Alegre: Bookman, 2013.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- PEREIRA, L. C. SIG com QGIS. São Paulo: Novatec, 2020.\n- BRASIL. ANA. HidroWeb: Sistema de Informações Hidrológicas. Brasília: ANA, 2023.",
  "s6-planejamento": "# Planejamento Territorial\n\nInstrumentos de planejamento urbano e regional, uso e ocupação do solo, plano diretor municipal e sua interface com o planejamento de infraestrutura de saneamento.\n\n## Tópicos de Estudo\n\n- Planejamento urbano: conceito, história e modelos\n- Estatuto da Cidade (Lei nº 10.257/2001): instrumentos urbanísticos\n- Plano Diretor Municipal: conteúdo e elaboração participativa\n- Zoneamento urbano e uso e ocupação do solo\n- Parcelamento do solo urbano (Lei nº 6.766/1979)\n- Planejamento regional e metropolização\n- Interface do plano diretor com o PMSB (Plano Municipal de Saneamento Básico)\n- Geoprocessamento no planejamento territorial\n- Habitação e regularização fundiária\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Lei nº 10.257/2001 – Estatuto da Cidade. Brasília, 2001.\n- ROLNIK, R. A Cidade e a Lei. 3ª ed. São Paulo: FAPESP/Nobel, 1999.\n- SOUZA, M. L. Mudar a Cidade. 9ª ed. Rio de Janeiro: Bertrand Brasil, 2013.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BRASIL. Ministério das Cidades. Guia para Elaboração de Planos Municipais de Saneamento Básico. Brasília: MCidades, 2011.\n- DAVIS, M. Planeta Favela. São Paulo: Boitempo, 2006.",
  "s6-residuos-2": "# Gerenciamento de Resíduos Sólidos II\n\nTratamento, valorização e destinação final de resíduos sólidos: aterros sanitários, compostagem, digestão anaeróbia, incineração e resíduos especiais.\n\n## Tópicos de Estudo\n\n- Aterro sanitário: localização, projeto, operação e encerramento\n- Aterro controlado e lixão: passivos ambientais e remediação\n- Compostagem: processo, parâmetros e qualidade do composto\n- Digestão anaeróbia de resíduos: biogás e biometano\n- Incineração e co-processamento em fornos de cimento\n- Resíduos da Construção Civil (RCC): CONAMA 307/2002\n- Resíduos de Serviços de Saúde (RSS): RDC ANVISA 222/2018\n- Resíduos industriais perigosos: armazenamento e destinação\n- Logística reversa: embalagens, eletroeletrônicos e pilhas\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- BRASIL. Lei nº 12.305/2010 – Política Nacional de Resíduos Sólidos. Brasília, 2010.\n- LIMA, L. M. Q. Tratamento de Lixo. 2ª ed. São Paulo: Hemus, 1991.\n- ABNT. NBR 13896:1997 – Aterros de Resíduos não Perigosos. Rio de Janeiro: ABNT, 1997.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BIDONE, F. R. A.; POVINELLI, J. Conceitos Básicos de Resíduos Sólidos. São Carlos: EESC-USP, 1999.\n- BRASIL. Resolução CONAMA nº 307/2002 – Resíduos da Construção Civil. Brasília: MMA, 2002.",
  "s6-reuso": "# Reuso de Água\n\nFundamentos, normas, tecnologias e gestão do reúso de água em aplicações urbanas, industriais e agrícolas, com enfoque na sustentabilidade hídrica.\n\n## Tópicos de Estudo\n\n- Conceito e categorias de reúso de água (potável e não potável)\n- Legislação nacional sobre reúso: Resolução ANA nº 54/2005 e atualizações\n- Padrões de qualidade para reúso urbano e industrial\n- Sistemas de coleta e tratamento de águas cinzas\n- Aproveitamento de água de chuva (NBR 15527:2019)\n- Reúso agrícola: critérios de qualidade e riscos sanitários\n- Reúso industrial: torres de resfriamento e processos produtivos\n- Casos de referência: Singapura (NEWater) e Israel\n- Viabilidade econômica de projetos de reúso\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- ANA. Guia de Reúso de Água no Brasil. Brasília: ANA, 2022.\n- MANCUSO, P. C. S.; SANTOS, H. F. (ed.). Reúso de Água. Barueri: Manole, 2003.\n- ABNT. NBR 15527:2019 – Aproveitamento de Água de Chuva. Rio de Janeiro: ABNT, 2019.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- HESPANHOL, I. Potencial de Reúso de Água no Brasil. Belo Horizonte: UFMG, 2008.\n- OMS. WHO Guidelines for the Safe Use of Wastewater. Genebra: OMS, 2006.",
  "s6-trat-residuarias-2": "# Tratamento de Águas Residuárias II\n\nTratamento avançado de efluentes, reúso de água, processos de desinfecção avançados, tratamento de efluentes industriais e gestão do lodo de ETEs.\n\n## Tópicos de Estudo\n\n- Tratamento terciário: remoção de nutrientes (N e P)\n- Processos oxidativos avançados (POAs): ozonização e UV/H₂O₂\n- Desinfecção avançada: cloro, UV e peróxido de hidrogênio\n- Membranas de filtração: microfiltração, ultrafiltração e osmose reversa\n- Tratamento de efluentes industriais: indústrias de alimentos, têxtil e petroquímica\n- Gestão e tratamento do lodo de ETE: adensamento, digestão e desaguamento\n- Destinação do biossólido: compostagem e uso agrícola (CONAMA 375/06)\n- Reúso de água: categorias e normas (NBR 13969 e resolução ANA)\n- Eficiência energética em ETEs: biogás do lodo\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- JORDÃO, E. P.; PESSÔA, C. A. Tratamento de Esgotos Domésticos. 7ª ed. Rio de Janeiro: SEGRAC, 2014.\n- METCALF & EDDY. Wastewater Engineering: Treatment and Resource Recovery. 5ª ed. New York: McGraw-Hill, 2014.\n- VON SPERLING, M. Lodos Ativados. 3ª ed. Belo Horizonte: UFMG, 2012.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- BRASIL. Resolução CONAMA nº 375/2006 – Uso Agrícola de Lodos de ETEs. Brasília, 2006.\n- ANA. Guia de Reúso de Água no Brasil. Brasília: ANA, 2022.",
  "s7-tcc": "# Trabalho de Conclusão de Curso (TCC)\n\nDesenvolvimento de pesquisa ou projeto técnico original em saneamento ambiental, sob orientação docente, culminando com defesa pública perante banca examinadora.\n\n## Tópicos de Estudo\n\n- Definição do tema e revisão bibliográfica sistemática\n- Elaboração do projeto de pesquisa e metodologia\n- Coleta e análise de dados (qualitativos e/ou quantitativos)\n- Estrutura do TCC conforme normas ABNT (NBR 14724)\n- Redação científica: introdução, revisão, métodos, resultados e discussão\n- Referências bibliográficas (NBR 6023) e citações (NBR 10520)\n- Preparação da apresentação oral: slides e comunicação técnica\n- Defesa pública perante banca examinadora\n- Publicação e divulgação dos resultados: artigo científico\n\n## Bibliografia\n\n### 📚 BIBLIOGRAFIA BÁSICA\n- LAKATOS, E. M.; MARCONI, M. A. Fundamentos de Metodologia Científica. 7ª ed. São Paulo: Atlas, 2010.\n- GIL, A. C. Como Elaborar Projetos de Pesquisa. 5ª ed. São Paulo: Atlas, 2010.\n- ABNT. NBR 14724:2011 – Trabalhos Acadêmicos – Apresentação. Rio de Janeiro: ABNT, 2011.\n### 📗 BIBLIOGRAFIA COMPLEMENTAR\n- SEVERINO, A. J. Metodologia do Trabalho Científico. 23ª ed. São Paulo: Cortez, 2007.\n- ABNT. NBR 6023:2018 – Referências – Elaboração. Rio de Janeiro: ABNT, 2018."
};
